(function(){
  var loaded=false;
  var observer=window.__speedObserver;

  function loadAll(){
    if(loaded) return;
    loaded=true;
    if(observer) observer.disconnect();

    document.querySelectorAll("iframe[data-src]").forEach(function(el){
      if(el.dataset.src) el.src=el.dataset.src;
    });

    var scripts=document.querySelectorAll("script[data-src],script[type='text/lazyload']");
    scripts.forEach(function(s){
      var ns=document.createElement("script");
      for(var i=0;i<s.attributes.length;i++){
        var a=s.attributes[i];
        if(a.name==="type"&&a.value==="text/lazyload") continue;
        if(a.name==="data-src"){
          ns.setAttribute("src",a.value);
        } else {
          ns.setAttribute(a.name,a.value);
        }
      }
      ns.type="text/javascript";
      if(s.innerHTML) ns.innerHTML=s.innerHTML;
      if(s.parentNode) s.parentNode.replaceChild(ns,s);
    });

    document.querySelectorAll("link[data-href]").forEach(function(l){
      l.setAttribute("href",l.getAttribute("data-href"));
      l.removeAttribute("data-href");
    });

    document.dispatchEvent(new CustomEvent("asyncLazyLoad"));
  }

  var EVENTS=["mousedown","mousemove","keydown","scroll","touchstart","click","keypress","touchmove","pointerdown"];
  EVENTS.forEach(function(e){
    window.addEventListener(e,loadAll,{once:true,passive:true});
  });

  window.addEventListener("load",function(){
    setTimeout(function(){
      if(!loaded) loadAll();
    }, 5000);
  });
})();
